# -*- coding: utf-8 -*-
from docx import Document
from pathlib import Path

path = Path(r"D:\bishe\one\tmp_thesis_567.docx")
doc = Document(str(path))

mapping = [
    ('对学生而言，传统教务系统在信息组织上通常比较规范，菜单、表单和制度说明都不缺，但真正使用时，学生遇到的麻烦往往不是“没有入口”，而是“看见入口以后还是不明白怎么走下一步”。例如选课信息能查到，请假页面也能打开，办事大厅也有事项列表，可一旦涉及办理条件、材料差异、流程顺序或者课程内容理解，静态页面就很难继续承担解释工作。这正是学生侧需要引入自然语言帮助的直接原因。', '学生角色需求分析'),
    ('对教师而言，教师在教务系统中的工作，一部分是确定性的，如课程管理、成绩处理、审批等；另一部分却高度依赖经验和内容组织，比如整理课程资料、反复回答共性问题、准备教案和教学提纲。前一部分传统教务系统已经覆盖得比较成熟，后一部分长期依赖人工完成，工作量零散却持续。正因为这种结构性差异，教师对AI的需求天然会落在“围绕课程内容减轻重复劳动”上。', '教师角色需求分析'),
    ('管理员的关注点又明显不同。管理员并不是主要提问者，但必须保证AI能力可以被稳定、可控地使用。这就带来了几项很现实的需求：模型接入方式要清楚，知识资料的归属要明确，不同场景要有对应的工作流，配置变更后前台页面还要能够及时生效。换句话说，管理员面对的是治理需求，而不是单纯的使用需求。', '管理员治理需求分析'),
    ('如果把三类角色放到同一条业务线上看，系统至少要支撑三种典型场景。第一类是学生咨询场景，围绕选课、请假、办事和学习问题提供即时解释；第二类是课程答疑场景，由教师整理课程资料、学生围绕课程继续提问；第三类是教学生成场景，教师依据已有课程资源形成教案草稿并再加工。这些场景彼此并不割裂，它们都依赖课程数据、角色权限和知识资料的协同。', '典型AI业务场景归纳'),
    ('因此，基础教务功能首先需要保持完整和稳定。学生要能够完成课程查询、请假申请、成绩与证书查看、办事事项办理；教师要能够完成课程管理、作业与成绩处理、审批等教学组织工作；管理员要能够维护用户、流程和系统配置。这部分功能决定了系统的业务边界，也为AI判断面向谁服务、在什么场景下服务提供了前提。', '基础教务功能需求'),
    ('在此基础上，AI客服的功能需求主要体现为规则解释与入口引导。它要承接校园常见问题、办事咨询和流程说明，在页面中给出较为及时的反馈，并在知识不足时明确提示用户继续查看哪类业务入口或联系哪一类管理人员。这里的重点不是让AI代替业务办理，而是帮助用户更快理解业务。', 'AI客服功能需求'),
    ('AI课程助手的功能需求更贴近课程场景。系统需要支持教师围绕具体课程整理资料、形成课程专属问答入口，学生再根据所选课程获取学习支持。这样一来，问答内容就不再停留在通用校园咨询，而是能够落到某门课程的知识点、资料范围和教学要求上。对教师而言，这项功能的核心价值在于把分散资料逐步转化为可持续复用的课程服务能力。', 'AI课程助手功能需求'),
    ('智能教案模块则属于更典型的任务型功能。教师在备课时通常不会满足于一次性生成一段文本，而是希望系统围绕课程主题、资料基础和教学目标持续给出可修改、可保存、可导出的结果。所以这一模块的需求重点应放在过程完整性上，包括任务发起、生成反馈、结果编辑、历史保留和再次使用，而不是单独强调生成速度。', '智能教案功能需求'),
    ('从整体上看，AI增强功能可以归纳为三类需求：一类是配置类需求，确保管理员能够为不同场景准备合适的模型和知识资源；一类是交互类需求，确保学生和教师能在合适页面发起提问或生成请求，并清楚感知系统状态；另一类是沉淀类需求，确保文档、问答结果和教案内容能够被保存下来，服务下一轮课程答疑、教学准备和系统优化。这样划分之后，AI客服、AI课程助手和智能教案虽然面向对象不同，但在系统中的定位就比较清楚了。', 'AI增强需求归类'),
    ('除功能本身外，系统还需要满足较为明确的非功能需求。首先是可用性需求。高校教务业务往往具有时间敏感和流程敏感的特点，用户常常是在选课、请假、成绩查询或备课过程中临时进入系统，如果页面入口不清晰、反馈不及时，AI能力即便已经接入，也很难形成稳定的使用习惯。因此，系统需要在不同角色下提供清楚的入口组织和易于理解的操作反馈。', '可用性需求'),
    ('其次是响应连续性需求。问答和内容生成与传统表单提交不同，用户更关心系统是否正在处理。为此，系统需要让返回过程具备可感知的连续反馈，而不是长时间无响应。论文中采用的服务器发送事件（Server-Sent Events，SSE）机制，本质上对应的就是这一类需求：让用户在等待结果时持续看到系统状态变化，从而降低不确定感。', '响应连续性需求'),
    ('再次是可靠性与可追踪性需求。无论是课程资料上传、课程问答，还是教案生成，用户都希望知道操作是否成功、当前处于什么状态、出现问题后能否定位原因。尤其是教师侧的课程助手和智能教案，一旦缺少过程记录，后续修改、复查和复用都会受到影响。因此，系统不仅要能生成，还要能说明过程、能保留结果。', '可靠性与可追踪性需求'),
    ('安全与权限控制同样不可忽视。教务系统包含用户身份、课程信息、申请记录和教学资料等数据，不同角色的可见范围和可操作范围必须区分清楚。学生更偏向使用结果，教师需要管理课程资料，管理员负责配置和治理，这种权限差异决定了系统必须在访问入口、配置操作和数据归属上保持边界清晰，避免出现越权访问或资源混用。', '安全与权限控制需求'),
    ('最后是部署与维护需求。毕业设计的展示并不只发生在本地开发环境中，还要考虑教师评审、远程访问和后续演示的实际需要。因此，系统应同时支持本地联调与公网访问场景。当前项目除支持本地启动外，还通过部署在阿里云云服务器 Ubuntu 系统上的站点对外提供服务，并可通过公网域名wangjiaqi.me直接访问。这类需求虽然不直接体现为页面功能，却决定了系统能否稳定演示、持续维护和方便扩展。', '部署与维护需求'),
    ('为满足高校教务场景下多角色访问、业务协同、AI接入与数据治理等需求，系统总体采用“前端展示层—后端服务层—AI能力层—数据与外部资源层”的分层架构。前端展示层负责承载学生、教师和管理员的业务入口与交互反馈；后端服务层负责统一接口组织、权限校验与业务编排；AI能力层负责模型调用、知识检索和内容生成；数据与外部资源层负责保存教务数据、AI配置数据、知识文档及外部模型服务连接信息[6]。', '分层架构设计思路'),
    ('按照上述分层设计，系统通过统一接口出口连接普通教务模块与AI模块，使课程、请假、办事大厅、成绩、课程助手、AI客服和智能教案等功能能够在同一权限体系下协同运行。学生端与教师端围绕具体业务页面发起问答或生成请求，管理员端负责模型、知识库和工作流的配置治理；前端请求经后端服务层汇总后，再由AI能力层完成知识匹配与模型推理，并将结果回写到页面或任务记录中。由此，系统总体架构的重点不在于单一技术组件的堆叠，而在于角色入口、业务服务与AI资源编排之间形成稳定、清晰的协作关系。', '业务与AI协同关系'),
    ('从总体设计视角看，系统由基础教务支撑模块、AI资源治理模块、AI业务接入模块和结果沉淀反馈模块四部分协同构成。基础教务支撑模块负责课程、请假、办事大厅、成绩与用户管理等原生业务；AI资源治理模块负责模型、知识库与工作流的统一配置；AI业务接入模块负责将AI能力以客服、课程助手和智能教案等形式提供给不同角色；结果沉淀反馈模块负责保存知识文档、问答调用记录和教案任务结果。', '模块组成设计'),
    ('这种模块划分方式的意义在于，它明确了AI在系统中的职责边界。基础教务模块仍然承担规则执行与流程办理，AI模块主要承担解释、增强和辅助生成作用；管理员负责治理底层AI资源，教师负责组织课程资料并开展教学辅助，学生则主要面向问答与使用结果。模块边界清晰后，系统才能避免“AI替代全部业务”的误解，并形成更适合高校教务场景的工程落地结构。', '模块边界说明'),
    ('数据库总体规划是总体设计中的基础工作，它不只是保存页面结果，还承担着组织系统运行逻辑的作用。结合本项目的业务特点，数据库可以按数据职责分为五个部分：第一类是用户、课程、请假、成绩、办事等基础教务数据，用来支撑系统原有业务流程；第二类是模型、知识库与工作流等AI资源配置数据，用来说明AI能力由谁维护、面向什么场景开放；第三类是课程资料、制度文档及其整理结果，用来形成可持续调用的知识来源；第四类是教案生成等任务过程数据，用来记录任务发起、处理中和完成后的状态变化；第五类是问答记录、调用状态与运行痕迹数据，用来支撑后续复查、统计与优化。', '数据分类思路'),
    ('从组织方式上看，这些数据并不是彼此孤立保存，而是围绕用户、课程、知识资料和AI场景逐层关联。基础教务数据负责提供角色身份和课程边界，AI配置数据负责确定调用关系，知识数据负责提供内容依据，任务与日志数据负责保留运行结果。这样的规划能够较清楚地回答三个问题：AI能力由谁配置、依赖哪些资料、最终结果保存在哪里，也使系统在后续扩展课程答疑、教学生成或使用统计时具备较好的结构基础。', '数据关联逻辑'),
    ('结合本项目的业务组织方式，可以把AI功能主线概括为“配置准备、场景调用、结果沉淀、持续优化”四个连续环节。首先由管理员完成模型、知识资料和场景参数的准备，使系统具备可调用的AI底座；随后由学生和教师在具体页面中发起咨询、课程答疑或教案生成请求；系统运行后会把问答记录、课程资料变化、任务状态和生成结果保留下来；这些沉淀的数据又会反过来支持知识补充、配置调整和场景优化。这样形成的并不是一次性的调用链，而是一条能够持续迭代的业务闭环。', '闭环运行主线'),
    ('为了让这一闭环能够稳定落到系统结构中，本文进一步将AI部分概括为四层设计：AI配置编排层负责模型接入和场景组织，知识组织层负责整理制度文档与课程资料，推理执行层负责完成问题理解、知识匹配和内容生成，业务接入层负责把这些能力开放给AI客服、AI课程助手和智能教案等具体入口。这种写法强调的是设计层次，而不是把实现细节直接搬到需求分析中，也更符合本章从总体设计出发的叙述逻辑。', '分层闭环设计'),
    ('前面的需求分析与总体设计明确了系统要解决什么问题，而关键技术选择则回答系统依靠什么把这些能力稳定落到项目中。考虑到本课题既包含课程管理、请假、办事大厅等传统教务业务，又要承载AI客服、AI课程助手和智能教案等新增能力，技术方案不能只追求复杂堆叠，而应服务于结构清晰、部署简洁、便于演示和后续扩展这几个现实目标。', '关键技术选型原则'),
    ('在系统架构层面，项目采用前后端分离方式组织多角色业务。前端主要负责学生、教师和管理员页面中的表单交互、状态反馈与结果展示，后端负责权限校验、业务编排、统一接口输出以及模型调用衔接。这样的划分使角色页面与AI服务链路能够相对独立演进，后续即使继续扩展课程助手或新增新的智能功能，也不必反复改动整套页面逻辑。', '前后端协同支撑'),
    ('在AI能力组织层面，系统没有直接把大模型嵌入单一聊天页面，而是通过模型配置、知识库、工作流应用和任务记录等对象组织运行过程。配合文档抽取、文本分块和轻量级检索增强生成机制，制度说明、课程资料和教师上传内容可以逐步转化为可检索、可追溯的知识来源。这种做法既贴合本项目当前中小规模资料场景，也更便于说明回答依据来自哪里。', 'AI资源组织支撑'),
    ('在交互与部署层面，系统采用模型分级选择策略与SSE流式返回机制。前者保证不同场景能够按工作流或默认策略调用合适模型，后者让用户在问答和教案生成过程中持续看到输出变化，减轻等待时的不确定感。结合本地开发环境与阿里云服务器部署环境，这套技术组合已经能够支撑项目联调、答辩演示和公网访问需求。', '流式交互与部署支撑'),
]

pairs = []
for i, p in enumerate(doc.paragraphs):
    text = p.text.strip()
    for target, heading in mapping:
        if text == target:
            pairs.append((i, p, heading))
            break

if len(pairs) != len(mapping):
    found = {heading for _, _, heading in pairs}
    missing = [heading for _, heading in mapping if heading not in found]
    raise SystemExit('missing:' + '|'.join(missing))

for _, para, heading in sorted(pairs, key=lambda x: x[0], reverse=True):
    new_p = para.insert_paragraph_before(heading)
    new_p.style = doc.styles['Heading 3']

doc.save(str(path))
print('saved', path)
